@import url("https://fonts.googleapis.com/css2?family=Bebas+Neue&family=Montserrat:wght@400;500;600;700;800&family=Playfair+Display:ital@1&display=swap");

:root {
  color-scheme: dark;

  --hlg-red: #cc0000;
  --hlg-black: #111111;
  --hlg-white: #ffffff;
  --hlg-future: #4caf50;
  --hlg-ride: #1e90ff;
  --hlg-racing: #cc0000;

  --bg: #080808;
  --surface: #121212;
  --surface-strong: #050505;
  --surface-raised: #191919;
  --fg: #ffffff;
  --muted: #b8b8b8;
  --muted-2: #777777;
  --border: rgba(255, 255, 255, 0.16);
  --border-strong: rgba(255, 255, 255, 0.32);
  --accent: var(--hlg-red);
  --line-red: #cc0000;

  --future: var(--hlg-future);
  --ride: var(--hlg-ride);
  --racing: var(--hlg-racing);
  --success: #4caf50;
  --info: #1e90ff;
  --warning: #ffc94a;
  --danger: #cc0000;

  --font-display: "Bebas Neue", "Arial Narrow", Impact, sans-serif;
  --font-body: "Montserrat", -apple-system, BlinkMacSystemFont, "Segoe UI", system-ui, sans-serif;
  --font-emphasis: "Playfair Display", Georgia, serif;
  --font-mono: "SFMono-Regular", Consolas, "Liberation Mono", monospace;

  --space-1: 4px;
  --space-2: 8px;
  --space-3: 12px;
  --space-4: 16px;
  --space-5: 24px;
  --space-6: 32px;
  --space-7: 48px;
  --space-8: 64px;
  --space-9: 96px;

  --radius-badge: 6px;
  --radius-button: 8px;
  --radius-panel: 12px;
  --radius-large: 18px;

  --shadow-red: 0 0 24px rgba(204, 0, 0, 0.32);
  --shadow-panel: 0 22px 80px rgba(0, 0, 0, 0.42);
  --overlay-soft: linear-gradient(180deg, rgba(0, 0, 0, 0.18), rgba(0, 0, 0, 0.72));
  --overlay-strong: linear-gradient(90deg, rgba(0, 0, 0, 0.88), rgba(0, 0, 0, 0.58), rgba(0, 0, 0, 0.12));
}

* {
  box-sizing: border-box;
}

body {
  margin: 0;
  background: var(--bg);
  color: var(--fg);
  font-family: var(--font-body);
  -webkit-font-smoothing: antialiased;
  text-rendering: optimizeLegibility;
}

.hlg-display {
  font-family: var(--font-display);
  font-weight: 400;
  text-transform: uppercase;
  letter-spacing: 0.012em;
  line-height: 0.9;
}

.hlg-emphasis {
  font-family: var(--font-emphasis);
  font-style: italic;
  font-weight: 400;
}

.hlg-kicker,
.hlg-button,
.hlg-badge {
  font-family: var(--font-body);
  font-weight: 800;
  text-transform: uppercase;
  letter-spacing: 0.14em;
}

.hlg-rule {
  display: block;
  width: 120px;
  height: 2px;
  background: var(--line-red);
  box-shadow: var(--shadow-red);
}

.hlg-panel {
  background: color-mix(in srgb, var(--surface) 92%, white 8%);
  border: 1px solid var(--border);
  border-radius: var(--radius-panel);
}

.hlg-button {
  display: inline-flex;
  min-height: 48px;
  align-items: center;
  justify-content: center;
  gap: 10px;
  border: 0;
  border-radius: var(--radius-button);
  background: var(--accent);
  color: var(--hlg-white);
  padding: 0 22px;
  text-decoration: none;
  box-shadow: var(--shadow-red);
}

.hlg-badge {
  display: inline-flex;
  align-items: center;
  border: 1px solid var(--accent);
  border-radius: var(--radius-badge);
  color: var(--accent);
  padding: 8px 12px;
  background: rgba(204, 0, 0, 0.1);
}

